insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:match:a9808972', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Encryption”?", "options": ["Scans files, detects malware using a database of known signatures, and quarantines or removes it", "Scrambles data using an algorithm and a key so that, if intercepted, it cannot be understood", "Protects the hardware itself using locks, keycards, biometrics, CCTV or a locked server room", "A long, varied, unique password that greatly increases the combinations a brute-force attack must try"]}'::jsonb, '{"answer": 1, "explain": "“Encryption” means: Scrambles data using an algorithm and a key so that, if intercepted, it cannot be understood"}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:match:d46c4785', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Caesar cipher”?", "options": ["Scrambles data using an algorithm and a key so that, if intercepted, it cannot be understood", "Requires a second factor, such as a code sent to a phone, in addition to the password", "A simple encryption method that shifts each letter along the alphabet by a fixed key", "Teaches people to recognise phishing and other social engineering so they are not tricked"]}'::jsonb, '{"answer": 2, "explain": "“Caesar cipher” means: A simple encryption method that shifts each letter along the alphabet by a fixed key"}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:match:27cb033d', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Physical security”?", "options": ["Teaches people to recognise phishing and other social engineering so they are not tricked", "Scrambles data using an algorithm and a key so that, if intercepted, it cannot be understood", "Written rules setting out how systems, passwords and software may be used in an organisation", "Protects the hardware itself using locks, keycards, biometrics, CCTV or a locked server room"]}'::jsonb, '{"answer": 3, "explain": "“Physical security” means: Protects the hardware itself using locks, keycards, biometrics, CCTV or a locked server room"}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:match:05b38ecd', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Staff training”?", "options": ["An authorised, simulated attack used to find weaknesses so they can be fixed before a real attacker exploits them", "Requires a second factor, such as a code sent to a phone, in addition to the password", "Teaches people to recognise phishing and other social engineering so they are not tricked", "Protects the hardware itself using locks, keycards, biometrics, CCTV or a locked server room"]}'::jsonb, '{"answer": 2, "explain": "“Staff training” means: Teaches people to recognise phishing and other social engineering so they are not tricked"}'::jsonb),
('computer-science:1-4-2-identifying-and-preventing-vulnerabilities:match:fc4a6ede', 'computer-science', 'computer-science:1-4-2-identifying-and-preventing-vulnerabilities', '1.4.2 Identifying and Preventing Vulnerabilities', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Acceptable-use policy”?", "options": ["Requires a second factor, such as a code sent to a phone, in addition to the password", "Written rules setting out how systems, passwords and software may be used in an organisation", "Monitors and filters incoming and outgoing network traffic against a set of rules", "Protects the hardware itself using locks, keycards, biometrics, CCTV or a locked server room"]}'::jsonb, '{"answer": 1, "explain": "“Acceptable-use policy” means: Written rules setting out how systems, passwords and software may be used in an organisation"}'::jsonb),
('computer-science:1-5-1-operating-systems:exam:47541456', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'exam', 'mcq', 1, '{"num": "Q1", "question": "<p>Tick <strong>one</strong> box to identify the operating system function that provides the means by which a user interacts with the computer.</p>", "options": ["Memory management", "The user interface", "File management", "Peripheral management"], "hint": "Which function is about how a person gives the computer instructions and sees its output?"}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>The user interface</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "The user interface."}'::jsonb),
('computer-science:1-5-1-operating-systems:exam:4316610b', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'exam', 'mcq', 1, '{"num": "Q2", "question": "<p>Tick <strong>one</strong> box to identify the operating system function responsible for allocating RAM to programs and moving data into and out of main memory.</p>", "options": ["File management", "Memory management", "User management", "Multitasking"], "hint": "The clue is ''RAM'' and ''main memory'' — only one function is about managing that."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Memory management</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "Memory management."}'::jsonb),
('computer-science:1-5-1-operating-systems:exam:7df32cf5', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'exam', 'mcq', 1, '{"num": "Q3", "question": "<p>Tick <strong>one</strong> box to identify which of these is a task performed by file management.</p>", "options": ["Switching the processor between several open programs", "Renaming a folder", "Installing a driver for a new scanner", "Allocating memory to a program"], "hint": "File management is about organising files and folders on the computer."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Renaming a folder</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "Renaming a folder."}'::jsonb),
('computer-science:1-5-1-operating-systems:mcq:fa960227', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'mcq', 'mcq', 1, '{"question": "Which of the following is an example of an operating system?", "options": ["A spreadsheet program that a user opens whenever they need to work with numbers and charts", "Linux", "A device driver that has been installed so the computer can print to a new office printer", "A backup utility that automatically copies important files to an external drive each night"]}'::jsonb, '{"answer": 1, "explain": "Linux is an operating system. A spreadsheet is application software, and a driver or backup utility is other system software — not the OS itself."}'::jsonb),
('computer-science:1-5-1-operating-systems:mcq:cbcc30e3', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'mcq', 'mcq', 1, '{"question": "What is the main purpose of the user interface provided by an operating system?", "options": ["To permanently increase the amount of storage space available on the computer''s hard drive", "To provide the means by which a user interacts with the computer and gives it instructions", "To scan the computer for malware and remove any harmful programs that it happens to find", "To keep a spare copy of every file so that nothing is ever lost if the computer breaks down"]}'::jsonb, '{"answer": 1, "explain": "The user interface is how the user interacts with the computer (e.g. a GUI or CLI) — it does not manage storage, malware or backups."}'::jsonb),
('computer-science:1-5-1-operating-systems:mcq:bc2a9702', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'mcq', 'mcq', 1, '{"question": "A single-processor computer has a browser, a game and a music player all open at the same time. Which operating system function makes this possible?", "options": ["File management", "Multitasking", "User management", "Peripheral management"]}'::jsonb, '{"answer": 1, "explain": "Multitasking rapidly switches the processor between the open programs so they appear to run at the same time."}'::jsonb),
('computer-science:1-5-1-operating-systems:mcq:9bd226d0', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'mcq', 'mcq', 1, '{"question": "Which task is carried out by the memory management function?", "options": ["Organising the user''s saved documents and photos neatly into a set of clearly named folders", "Allocating space in RAM to each running program and moving data in and out of memory", "Requiring every user to enter a password before they are allowed to log in to the computer", "Sending data to a printer''s buffer so that several documents can be printed one after another"]}'::jsonb, '{"answer": 1, "explain": "Allocating RAM and moving data in and out of memory is memory management. The others are file management, user management and peripheral management."}'::jsonb),
('computer-science:1-5-1-operating-systems:mcq:e1791833', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'mcq', 'mcq', 1, '{"question": "Why does an operating system need a device driver for a new printer?", "options": ["Because the printer will physically refuse to switch on until a matching driver has been bought", "Because the driver is the software that lets the OS communicate with that specific printer", "Because a driver is the only thing that supplies electrical power to the printer while it runs", "Because without a driver the printer would print every document in completely the wrong order"]}'::jsonb, '{"answer": 1, "explain": "A driver is the software that lets the OS communicate with and control that specific device — it does not supply power or physically switch the printer on."}'::jsonb),
('computer-science:1-5-1-operating-systems:mcq:98da475f', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'mcq', 'mcq', 1, '{"question": "On a shared family computer, each person has their own login, their own files and their own settings. Which operating system function provides this?", "options": ["File management", "User management", "Memory management", "Multitasking"]}'::jsonb, '{"answer": 1, "explain": "Separate accounts, logins and settings are provided by user management, which also controls each user''s access rights."}'::jsonb),
('computer-science:1-5-1-operating-systems:mcq:85b0c4d1', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'mcq', 'mcq', 1, '{"question": "Which of these is a task performed by file management?", "options": ["Switching the processor rapidly between several different programs that the user has opened at once", "Creating, renaming, moving and deleting files within a structure of folders on the computer", "Translating the operating system''s instructions into commands a specific graphics card understands", "Deciding how much of the computer''s RAM each currently running program is allowed to use"]}'::jsonb, '{"answer": 1, "explain": "Creating, renaming, moving and deleting files in folders is file management. The others describe multitasking, drivers and memory management."}'::jsonb),
('computer-science:1-5-1-operating-systems:mcq:5072ac7b', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'mcq', 'mcq', 1, '{"question": "What does peripheral management use a buffer for?", "options": ["To permanently store all of the user''s most important files in case the computer ever breaks down completely", "To temporarily hold data waiting to be sent to a slower device, so the processor need not wait", "To make the processor run at a much higher clock speed than it was originally designed for", "To decide which of the computer''s several users is currently allowed to print their documents"]}'::jsonb, '{"answer": 1, "explain": "A buffer temporarily holds data waiting to be processed by a slower peripheral, so the fast processor is not held up waiting for it."}'::jsonb),
('computer-science:1-5-1-operating-systems:mcq:ab5630a1', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'mcq', 'mcq', 1, '{"question": "Which two functions must work together so that several programs can run at once without their data getting mixed up?", "options": ["File management and user management, because both of them deal with keeping things neatly separated", "Memory management and multitasking, because one keeps each program''s memory separate as the other switches between them", "Peripheral management and device drivers, because both of them handle the various hardware devices attached to the computer", "The user interface and file management, because both of them are things the user can see on the screen"]}'::jsonb, '{"answer": 1, "explain": "Multitasking switches between programs while memory management keeps each program''s memory separate, so their data does not get mixed up."}'::jsonb),
('computer-science:1-5-1-operating-systems:mcq:19b4519e', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'mcq', 'mcq', 1, '{"question": "A user types text commands to control a computer instead of clicking on icons. Which type of user interface are they using?", "options": ["A graphical user interface (GUI)", "A command line interface (CLI)", "A peripheral management interface", "A file management interface"]}'::jsonb, '{"answer": 1, "explain": "Typing text commands to control the computer is a command line interface (CLI); a GUI is controlled by clicking windows, icons, menus and a pointer."}'::jsonb),
('computer-science:1-5-1-operating-systems:mcq:c6f5e046', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'mcq', 'mcq', 1, '{"question": "Which of the following best describes what a graphical user interface (GUI) uses?", "options": ["Typed text commands that the user has to learn and remember before they can do anything at all", "Windows, icons, menus and a pointer that the user can click on to control the computer", "A single flashing cursor on an otherwise completely blank screen with no other options shown", "A printed paper manual that lists every command the computer is able to understand and carry out"]}'::jsonb, '{"answer": 1, "explain": "A GUI uses windows, icons, menus and a pointer (WIMP). Typed commands describe a CLI, not a GUI."}'::jsonb),
('computer-science:1-5-1-operating-systems:mcq:9199a2df', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'mcq', 'mcq', 1, '{"question": "Which operating system function is responsible for setting each user''s access rights?", "options": ["Memory management", "User management", "File management", "Multitasking"]}'::jsonb, '{"answer": 1, "explain": "Setting access rights and permissions for each account is part of user management."}'::jsonb),
('computer-science:1-5-1-operating-systems:tf:a0f602db', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'tf', 'tf', 1, '{"question": "An operating system is an example of application software."}'::jsonb, '{"answer": false, "explain": "An operating system is system software. Application software (like a word processor) runs on top of the operating system."}'::jsonb),
('computer-science:1-5-1-operating-systems:tf:186a65ec', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'tf', 'tf', 1, '{"question": "A command line interface requires the user to type text commands to control the computer."}'::jsonb, '{"answer": true, "explain": "Correct — a CLI is controlled by typed commands, unlike a GUI which uses windows, icons, menus and a pointer."}'::jsonb),
('computer-science:1-5-1-operating-systems:tf:72befc2c', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'tf', 'tf', 1, '{"question": "Memory management is responsible for organising the user''s saved files into folders."}'::jsonb, '{"answer": false, "explain": "That is file management. Memory management deals with RAM — allocating it to programs and moving data in and out of it."}'::jsonb),
('computer-science:1-5-1-operating-systems:tf:2d1b8e53', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'tf', 'tf', 1, '{"question": "During multitasking, a single processor rapidly switches between programs so they appear to run at the same time."}'::jsonb, '{"answer": true, "explain": "Correct — one processor runs one instruction at a time, so it time-slices between programs, making them appear simultaneous."}'::jsonb),
('computer-science:1-5-1-operating-systems:tf:9a13c62f', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'tf', 'tf', 1, '{"question": "A device driver is a physical cable that connects a peripheral to the computer."}'::jsonb, '{"answer": false, "explain": "A device driver is software, not hardware. It lets the operating system communicate with a specific device."}'::jsonb),
('computer-science:1-5-1-operating-systems:tf:e86cbd13', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'tf', 'tf', 1, '{"question": "Peripheral management can use a buffer so the fast processor does not have to wait for a slower device."}'::jsonb, '{"answer": true, "explain": "Correct — a buffer temporarily holds data for a slower peripheral, letting the processor carry on with other work."}'::jsonb),
('computer-science:1-5-1-operating-systems:tf:026abcb9', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'tf', 'tf', 1, '{"question": "User management is what keeps different users'' files and settings separate and controls their access rights."}'::jsonb, '{"answer": true, "explain": "Correct — user management provides separate accounts with their own logins, settings and access rights."}'::jsonb),
('computer-science:1-5-1-operating-systems:tf:cb2af13b', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'tf', 'tf', 1, '{"question": "The user interface is the physical monitor and keyboard attached to the computer."}'::jsonb, '{"answer": false, "explain": "The user interface is the software layer (such as a GUI or CLI) through which the user interacts — not the physical hardware itself."}'::jsonb),
('computer-science:1-5-1-operating-systems:learn:8f4a930b', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'learn', 'mcq', 1, '{"readingTitle": "What is an operating system?", "reading": "<h4>The software that runs the whole computer</h4>\n<ul>\n<li>An <strong>operating system (OS)</strong> is <strong>system software</strong> that manages the computer''s hardware and software and provides a platform (a base) for application software to run on.</li>\n<li>It sits <strong>between the user and applications on one side and the hardware on the other</strong> — when a program wants to save a file or print, it asks the OS, and the OS deals with the hardware.</li>\n<li>It runs <strong>automatically</strong> when the computer starts and works in the background the whole time the computer is on. Examples include Windows, macOS, Linux, Android and iOS.</li>\n</ul>\n<h4>The five functions you must know</h4>\n<ul>\n<li>This topic is really about the <strong>jobs (functions)</strong> an OS does: the <strong>user interface</strong>, <strong>memory management &amp; multitasking</strong>, <strong>peripheral management &amp; drivers</strong>, <strong>user management</strong> and <strong>file management</strong>. The exam skill is knowing what each one does.</li>\n</ul>", "question": "Which statement best describes an operating system?", "options": ["A piece of application software, such as a word processor, that a user chooses to open in order to complete one particular task", "System software that manages the computer''s hardware and provides a platform for applications to run on", "A physical hardware component fitted inside the computer''s case to make it run more quickly", "A single file that stores all of the user''s personal documents, photos and settings together"]}'::jsonb, '{"answer": 1, "explain": "The OS is system software that manages the hardware and provides a platform for applications — it is not an application itself, nor a hardware part."}'::jsonb),
('computer-science:1-5-1-operating-systems:learn:eed0b6ea', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'learn', 'mcq', 1, '{"readingTitle": "The user interface", "reading": "<h4>How the user interacts with the computer</h4>\n<ul>\n<li>One job of the OS is to provide a <strong>user interface</strong> — the means by which a person <strong>interacts</strong> with the computer, giving it instructions and seeing its output.</li>\n<li>A <strong>graphical user interface (GUI)</strong> uses <strong>windows, icons, menus and a pointer</strong> (sometimes called WIMP). It is easy for beginners because you click and tap visible options rather than remembering commands.</li>\n<li>A <strong>command line interface (CLI)</strong> needs the user to <strong>type text commands</strong>. It is harder to learn, but can be faster and more powerful for experienced users.</li>\n</ul>", "question": "What is the main difference between a GUI and a command line interface (CLI)?", "options": ["A GUI uses windows, icons, menus and a pointer, whereas a CLI needs the user to type text commands", "A GUI can only ever be used on a mobile phone or a tablet, while a CLI can only be used on a desktop computer", "A GUI is a piece of hardware, whereas a CLI is a completely separate physical device from it", "A GUI runs without any operating system at all, but a CLI always requires one to be installed"]}'::jsonb, '{"answer": 0, "explain": "A GUI is interacted with visually (windows, icons, menus, pointer); a CLI requires typed text commands — both are just styles of user interface."}'::jsonb),
('computer-science:1-5-1-operating-systems:learn:7a385325', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'learn', 'mcq', 1, '{"readingTitle": "Memory management", "reading": "<h4>Sharing out RAM between programs</h4>\n<ul>\n<li><strong>Memory management</strong> controls how the computer''s <strong>main memory (RAM)</strong> is used.</li>\n<li>It <strong>moves programs and data into and out of RAM</strong> as they are needed, and <strong>allocates</strong> (gives out) a share of memory to each running program.</li>\n<li>It keeps each program''s memory <strong>separate</strong>, so one program cannot overwrite or interfere with another''s data, and <strong>frees up</strong> memory again when a program is closed so it can be reused.</li>\n</ul>", "question": "What does the memory management function of an operating system do?", "options": ["It permanently stores all of the user''s saved files and documents on the computer''s hard drive", "It allocates RAM to each running program and moves programs and data into and out of memory", "It controls exactly which websites the user is allowed to visit while they are online", "It physically increases the total amount of RAM that is fitted inside the computer"]}'::jsonb, '{"answer": 1, "explain": "Memory management allocates RAM to programs and moves programs/data in and out of memory — it does not deal with permanent storage or add physical RAM."}'::jsonb),
('computer-science:1-5-1-operating-systems:learn:19425043', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'learn', 'mcq', 1, '{"readingTitle": "Multitasking", "reading": "<h4>Running several programs ''at once''</h4>\n<ul>\n<li><strong>Multitasking</strong> lets the computer <strong>appear</strong> to run several programs at the same time — for example a browser, music player and word processor all open together.</li>\n<li>A single processor can only actually run <strong>one instruction at a time</strong>, so the OS <strong>switches very rapidly between the programs</strong>, giving each a tiny slice of processor time in turn (time-slicing).</li>\n<li>Because the switching happens so fast, it <strong>looks</strong> to the user as though everything is running simultaneously. Multitasking works closely with memory management, which keeps each program''s memory separate.</li>\n</ul>", "question": "How does an operating system with a single processor manage to multitask?", "options": ["It genuinely runs every single open program at exactly the same instant, using no switching of any kind at all", "It switches very rapidly between the programs, giving each a small slice of processor time in turn", "It shuts every program except one, and only reopens the others when the user asks for them again", "It permanently splits the processor into several smaller, separate physical processors inside the chip"]}'::jsonb, '{"answer": 1, "explain": "A single processor runs one instruction at a time, so the OS rapidly switches between programs (time-slicing) so they appear to run at once."}'::jsonb),
('computer-science:1-5-1-operating-systems:learn:4c8259b9', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'learn', 'mcq', 1, '{"readingTitle": "Peripheral management", "reading": "<h4>Controlling the devices connected to the computer</h4>\n<ul>\n<li><strong>Peripheral management</strong> controls communication between the computer and its <strong>peripherals</strong> — input, output and storage devices such as keyboards, printers, monitors and external drives.</li>\n<li>It <strong>manages the transfer of data to and from</strong> these devices, so that each one receives or sends data correctly.</li>\n<li>Because a device (like a printer) is usually much slower than the processor, the OS uses a <strong>buffer</strong> (a small store of data waiting to be processed) and a <strong>queue</strong> so the processor does not have to wait around for the device.</li>\n</ul>", "question": "What is the role of peripheral management in an operating system?", "options": ["It decides exactly which programs are allowed to appear in the computer''s start-up menu each and every morning", "It manages communication and the transfer of data between the computer and its connected devices", "It scans every file on the computer for viruses and other kinds of malicious software", "It chooses the strong passwords that each different user of the computer must use to log in"]}'::jsonb, '{"answer": 1, "explain": "Peripheral management handles communication and data transfer between the computer and its peripherals (input, output and storage devices)."}'::jsonb),
('computer-science:1-5-1-operating-systems:learn:7fd70e31', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'learn', 'mcq', 1, '{"readingTitle": "Device drivers", "reading": "<h4>Software that lets the OS ''talk to'' a device</h4>\n<ul>\n<li>A <strong>device driver</strong> is a piece of <strong>software</strong> that lets the operating system <strong>communicate with a specific piece of hardware</strong>, such as a particular printer, graphics card or webcam.</li>\n<li>It <strong>translates</strong> the operating system''s general instructions into the exact commands that <strong>that</strong> device understands.</li>\n<li>Each different device needs its <strong>own correct driver</strong>. If a driver is missing or out of date, the device may not work properly — which is why installing a new printer usually means installing its driver too.</li>\n</ul>", "question": "What is a device driver?", "options": ["A physical cable that is used to connect a peripheral device securely to the main computer unit", "Software that allows the operating system to communicate with a specific piece of hardware", "The person whose job it is to install and repair the computers within a large organisation", "A backup copy of the operating system that is used if the main copy ever becomes damaged"]}'::jsonb, '{"answer": 1, "explain": "A driver is software (not a cable or a person) that lets the OS communicate with, and control, a specific hardware device."}'::jsonb),
('computer-science:1-5-1-operating-systems:learn:ec83a1c2', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'learn', 'mcq', 1, '{"readingTitle": "User management", "reading": "<h4>Controlling accounts and who can do what</h4>\n<ul>\n<li><strong>User management</strong> lets the OS support <strong>different user accounts</strong>, each with its own <strong>login</strong> (username and password).</li>\n<li>It keeps each user''s <strong>files and settings separate</strong>, so one person''s documents and preferences do not mix with another''s.</li>\n<li>It sets <strong>access rights (permissions)</strong> — deciding what each user is allowed to see or do — and handles <strong>security</strong>, such as requiring a password to log in. This is how a shared computer can give a teacher more control than a student.</li>\n</ul>", "question": "Which of these is part of the user management function of an operating system?", "options": ["Moving programs and all of their data into and out of the computer''s main memory as they are needed to run", "Setting up user accounts with logins and giving each user their own access rights and permissions", "Sending pages of data to a printer''s buffer so they can be printed one after another in order", "Organising the computer''s saved files neatly into a structure of named folders and sub-folders"]}'::jsonb, '{"answer": 1, "explain": "User management deals with accounts, logins and access rights. The other options describe memory management, peripheral management and file management."}'::jsonb),
('computer-science:1-5-1-operating-systems:learn:a86f828c', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'learn', 'mcq', 1, '{"readingTitle": "File management", "reading": "<h4>Organising the files stored on the computer</h4>\n<ul>\n<li><strong>File management</strong> organises the files stored on the computer into a <strong>structure of folders (directories)</strong> so they can be found again easily.</li>\n<li>It lets the user (and programs) <strong>create, open, save, rename, move, copy and delete</strong> files and folders.</li>\n<li>It keeps track of <strong>where each file is physically stored</strong> on the disk, and can control <strong>who is allowed to access</strong> particular files, working alongside user management.</li>\n</ul>", "question": "What does the file management function of an operating system do?", "options": ["It rapidly switches the single processor between several open programs so they appear to run at once", "It organises files into folders and lets them be created, renamed, moved, copied, opened and deleted", "It translates the operating system''s instructions into commands that one specific printer understands", "It shares out the available space in RAM between all of the programs that are currently running"]}'::jsonb, '{"answer": 1, "explain": "File management organises files into folders and handles creating, naming, moving, copying and deleting them. The others describe multitasking, drivers and memory management."}'::jsonb),
('computer-science:1-5-1-operating-systems:learn:92577a82', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'learn', 'mcq', 1, '{"readingTitle": "Matching the function to the task", "reading": "<h4>The mapping the exam keeps testing</h4>\n<p>Questions very often give you a <strong>task</strong> and ask which <strong>function</strong> is responsible. Learn these signature links:</p>\n<ul>\n<li><strong>User interface</strong> → how the user <strong>interacts</strong> with the computer (clicking icons, typing commands).</li>\n<li><strong>Memory management</strong> → moving programs/data in and out of <strong>RAM</strong>; allocating memory.</li>\n<li><strong>Multitasking</strong> → switching between <strong>several open programs</strong> so they appear to run at once.</li>\n<li><strong>Peripheral management</strong> → transferring data <strong>to and from devices</strong>; using buffers.</li>\n<li><strong>Device drivers</strong> → letting the OS <strong>communicate with a specific device</strong> (e.g. installing a printer driver).</li>\n<li><strong>User management</strong> → <strong>accounts</strong>, logins, passwords and <strong>access rights</strong>.</li>\n<li><strong>File management</strong> → organising <strong>files and folders</strong> (create, rename, move, delete).</li>\n</ul>", "question": "A computer is ''transferring data to and from RAM as programs run''. Which operating system function is responsible?", "options": ["File management, because the data being transferred will eventually be saved into a folder somewhere", "Memory management, because it moves programs and data into and out of RAM and allocates memory", "User management, because only a logged-in user is able to run the programs on the computer at all", "Peripheral management, because RAM is a device that is connected to the rest of the computer system"]}'::jsonb, '{"answer": 1, "explain": "Moving programs and data in and out of RAM is the defining task of memory management."}'::jsonb),
('computer-science:1-5-1-operating-systems:misc:67d85d23', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking the operating system is the same thing as the applications, e.g. that a web browser or word processor is part of the OS.</p><p><strong>✅ The correct idea:</strong> The <strong>operating system</strong> is <strong>system software</strong> that manages the computer and provides a platform. <strong>Applications</strong> (browser, word processor, games) are separate software that <strong>runs on top of</strong> the OS. The OS is what lets those applications use the hardware.</p>", "question": "How is an operating system different from an application such as a web browser?", "options": ["There is no real difference between them, because both of them are simply types of application software", "The OS is system software that manages the computer; applications run on top of the OS", "The OS is a physical hardware component, while an application is a piece of software", "An application manages the hardware, while the operating system is only ever used for browsing the web"]}'::jsonb, '{"answer": 1, "explain": "The OS is system software that manages the machine and provides a platform; applications are separate software that runs on top of it."}'::jsonb),
('computer-science:1-5-1-operating-systems:misc:b3143316', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing that multitasking means a single processor genuinely runs many programs at exactly the same instant.</p><p><strong>✅ The correct idea:</strong> A single processor runs <strong>one instruction at a time</strong>. Multitasking works by <strong>switching very rapidly</strong> between the open programs, giving each a tiny slice of time. It only <strong>appears</strong> simultaneous because the switching is so fast.</p>", "question": "Why is it wrong to say a single-processor computer runs all its open programs at exactly the same instant?", "options": ["Because a single processor can only run one instruction at a time, so it must switch rapidly between them", "Because a single-processor computer can never actually have more than one separate program open at the same time at all", "Because programs never actually run on the processor, only ever on the RAM and the hard drive together", "Because the programs are really all run by the user manually, one instruction at a time, using the mouse"]}'::jsonb, '{"answer": 0, "explain": "One processor executes one instruction at a time; multitasking rapidly switches between programs so they only appear to run simultaneously."}'::jsonb),
('computer-science:1-5-1-operating-systems:misc:c798885c', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Confusing memory management (RAM) with managing the hard drive or saved files.</p><p><strong>✅ The correct idea:</strong> <strong>Memory management</strong> is about <strong>RAM</strong> — allocating it to running programs and moving programs and data in and out of it. Organising <strong>saved files</strong> in folders on storage is <strong>file management</strong>. Keep ''memory = RAM'' and ''files = storage'' separate.</p>", "question": "A question describes ''moving programs and data into and out of RAM''. Which function is this?", "options": ["File management, because anything to do with data on the computer counts as managing its files", "Memory management, because it is specifically about allocating and using RAM (main memory)", "User management, because a user must be logged in before any program can use the RAM at all", "Peripheral management, because RAM is treated as just another peripheral device by the computer"]}'::jsonb, '{"answer": 1, "explain": "Moving programs and data in and out of RAM is memory management; organising saved files on storage is the separate job of file management."}'::jsonb),
('computer-science:1-5-1-operating-systems:misc:88b252f2', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking a device driver is a physical part of the computer, or the person who installs it.</p><p><strong>✅ The correct idea:</strong> A <strong>device driver</strong> is <strong>software</strong>. It lets the operating system <strong>communicate with a specific piece of hardware</strong> by translating the OS''s instructions into commands that device understands. It is not a cable, a chip, or a person.</p>", "question": "Which statement about a device driver is correct?", "options": ["It is the wire that carries the electrical signal from the computer to a connected peripheral device", "It is software that lets the operating system communicate with a specific piece of hardware", "It is the member of IT staff whose job is to keep all of the school''s printers working properly", "It is a small physical chip that must be fitted inside every peripheral before it can be used"]}'::jsonb, '{"answer": 1, "explain": "A driver is software that lets the OS communicate with a specific device — not a cable, a chip or a person."}'::jsonb),
('computer-science:1-5-1-operating-systems:misc:cb7cbd21', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Mixing up user management and file management because both ''control access'' in some way.</p><p><strong>✅ The correct idea:</strong> <strong>User management</strong> is about the <strong>people</strong> — accounts, logins, passwords and each user''s access rights. <strong>File management</strong> is about the <strong>files</strong> — organising them into folders and creating, renaming, moving or deleting them. They work together but do different jobs.</p>", "question": "Which task belongs to user management rather than file management?", "options": ["Sorting all of the user''s saved documents and photographs neatly into a well-organised structure of named folders", "Setting up a new account with a login and giving that user their own access rights and permissions", "Renaming a file from ''draft'' to ''final'' after the user has finished working on the document", "Deleting an old folder full of files that the user says they no longer need to keep at all"]}'::jsonb, '{"answer": 1, "explain": "Creating accounts and setting access rights is user management; the other three tasks (organising, renaming and deleting files/folders) are file management."}'::jsonb),
('computer-science:1-5-1-operating-systems:misc:cbf4d7d7', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Assuming the user interface means the physical screen, mouse and keyboard.</p><p><strong>✅ The correct idea:</strong> The <strong>user interface</strong> is the <strong>software</strong> layer you interact through — a <strong>GUI</strong> (windows, icons, menus, pointer) or a <strong>CLI</strong> (typed commands). The monitor, mouse and keyboard are the hardware you use to work the interface, but they are not the interface itself.</p>", "question": "What is the user interface of an operating system?", "options": ["The physical monitor, keyboard and mouse that are plugged into the computer''s main unit by the user", "The software layer, such as a GUI or CLI, through which the user interacts with the computer", "The internal processor that carries out all of the instructions given to the computer by its user", "The broadband router that connects the whole computer to the internet and to other devices nearby"]}'::jsonb, '{"answer": 1, "explain": "The user interface is the software (GUI or CLI) you interact through; the physical devices are hardware used to operate it, not the interface itself."}'::jsonb),
('computer-science:1-5-1-operating-systems:tips:395797c8', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'tips', 'mcq', 1, '{"readingTitle": "tip — Match the function to the task — the tick-grid and table skill", "reading": "<p>The most common question style here gives you a <strong>task</strong> and asks which <strong>function</strong> does it — as a tick-one-box grid, or a table you complete. You have to know each function''s signature task cold:</p>\n<ul>\n<li>Transfer data to/from <strong>RAM</strong> → <strong>memory management</strong></li>\n<li>Install a printer''s <strong>driver</strong> / send data to a device → <strong>peripheral management</strong></li>\n<li>Create a <strong>user account</strong> / set a password → <strong>user management</strong></li>\n<li>Rename or move a <strong>folder</strong> → <strong>file management</strong></li>\n<li>Switch between several <strong>open programs</strong> → <strong>multitasking</strong></li>\n</ul>\n<p><strong>Watch the traps:</strong> \"memory\" means RAM, not storage — a saved file is <em>file</em> management. And installing a driver is <em>peripheral</em> management, even though the driver itself is software.</p>", "question": "In a tick-grid question, the task is ''renaming a folder''. Which function should you tick?", "options": ["Memory management, because the folder and its contents are stored somewhere in the computer''s memory", "File management, because renaming a folder is part of organising files and folders", "User management, because only a logged-in user is able to rename a folder in the first place", "Peripheral management, because the folder has to be shown on the monitor while it is renamed"]}'::jsonb, '{"answer": 1, "explain": "Renaming a folder is organising files and folders, which is file management — ''memory'' here would mean RAM, which is not involved."}'::jsonb),
('computer-science:1-5-1-operating-systems:tips:8a0c4052', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'tips', 'mcq', 1, '{"readingTitle": "explain — ''Identify and describe two functions'' — name AND describe", "reading": "<p>A frequent question asks you to <strong>identify and describe</strong> two (or more) functions of an operating system. The marks split into two halves for each function:</p>\n<ul>\n<li><strong>Identify (1 mark):</strong> name a valid function — e.g. \"memory management\".</li>\n<li><strong>Describe (1 mark):</strong> say what it actually does — e.g. \"it allocates RAM to each running program and moves data in and out of memory\".</li>\n</ul>\n<p><strong>❌ Half marks:</strong> just listing \"memory management, file management\" with no description.</p>\n<p><strong>✅ Full marks:</strong> each function <strong>named</strong> and then <strong>described</strong> with what it does. Pick functions you can clearly describe, and make sure your two functions are genuinely <strong>different</strong> — don''t give memory management twice in different words.</p>", "question": "A student answers a 4-mark ''identify and describe two functions'' question by writing only ''memory management and file management''. What is missing?", "options": ["Nothing is missing — naming the two functions is enough to earn all four of the available marks", "A description of what each named function actually does, which is where half of the marks are", "The exact year in which each of those two operating system functions was first invented", "A labelled diagram showing the inside of the processor while each function is running"]}'::jsonb, '{"answer": 1, "explain": "Naming the functions earns the ''identify'' marks only; the ''describe'' marks need you to say what each function does."}'::jsonb),
('computer-science:1-5-1-operating-systems:tips:6a794ddc', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'tips', 'mcq', 1, '{"readingTitle": "tip — Don''t blur memory, files, drivers and the interface", "reading": "<p>Four pairs get mixed up constantly. Keep each one crisp:</p>\n<ul>\n<li><strong>Memory management</strong> = RAM (main memory). <strong>File management</strong> = saved files/folders on storage. \"Memory\" ≠ \"storage\".</li>\n<li><strong>Peripheral management</strong> = the OS controlling devices. A <strong>device driver</strong> = the software that lets it talk to one specific device.</li>\n<li><strong>User interface</strong> = the software layer you interact through (GUI/CLI), not the physical screen or keyboard.</li>\n<li><strong>User management</strong> = accounts, logins and access rights (the people). <strong>File management</strong> = the files themselves.</li>\n</ul>\n<p>If a question mentions RAM, think memory management; if it mentions folders, think file management; if it mentions a specific printer or webcam, think drivers/peripheral management.</p>", "question": "A question mentions ''installing the software needed for the computer to use a new webcam''. Which term fits best?", "options": ["Memory management, because the webcam''s software will first need to be loaded into the computer''s RAM in order to run", "A device driver, because it is the software that lets the OS communicate with that specific webcam", "File management, because the webcam will end up saving its captured video files into a folder", "The user interface, because the user has to click on the webcam''s icon before they can use it"]}'::jsonb, '{"answer": 1, "explain": "The software that lets the OS use one specific device (the webcam) is its device driver."}'::jsonb),
('computer-science:1-5-1-operating-systems:fib:ace1462a', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'fib', 'fib', 1, '{"question": "An operating system is _____ software that manages the computer''s hardware and provides a platform for applications.", "blankOptions": {"B1": ["system", "driver", "folders", "user"]}}'::jsonb, '{"blanks": {"B1": "system"}}'::jsonb),
('computer-science:1-5-1-operating-systems:fib:0e2d9d63', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'fib', 'fib', 1, '{"question": "A graphical user interface uses windows, icons, menus and a _____ that the user clicks to control the computer.", "blankOptions": {"B1": ["pointer", "user", "driver", "multitasking"]}}'::jsonb, '{"blanks": {"B1": "pointer"}}'::jsonb),
('computer-science:1-5-1-operating-systems:fib:805f013a', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'fib', 'fib', 1, '{"question": "Memory management allocates space in _____ to each running program and moves data into and out of it.", "blankOptions": {"B1": ["driver", "folders", "user", "RAM"]}}'::jsonb, '{"blanks": {"B1": "RAM"}}'::jsonb),
('computer-science:1-5-1-operating-systems:fib:ccc82d42', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'fib', 'fib', 1, '{"question": "Because one processor runs a single instruction at a time, _____ makes several programs appear to run at once by switching between them.", "blankOptions": {"B1": ["folders", "multitasking", "user", "pointer"]}}'::jsonb, '{"blanks": {"B1": "multitasking"}}'::jsonb),
('computer-science:1-5-1-operating-systems:fib:3ff2cd3f', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'fib', 'fib', 1, '{"question": "A device _____ is software that lets the operating system communicate with a specific piece of hardware.", "blankOptions": {"B1": ["driver", "system", "buffer", "RAM"]}}'::jsonb, '{"blanks": {"B1": "driver"}}'::jsonb),
('computer-science:1-5-1-operating-systems:fib:6aedfdef', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'fib', 'fib', 1, '{"question": "Peripheral management uses a _____ to hold data waiting to be sent to a slower device such as a printer.", "blankOptions": {"B1": ["multitasking", "RAM", "buffer", "pointer"]}}'::jsonb, '{"blanks": {"B1": "buffer"}}'::jsonb),
('computer-science:1-5-1-operating-systems:fib:ec6e3cbd', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'fib', 'fib', 1, '{"question": "_____ management provides separate user accounts, logins and access rights on a shared computer.", "blankOptions": {"B1": ["buffer", "system", "user", "folders"]}}'::jsonb, '{"blanks": {"B1": "user"}}'::jsonb),
('computer-science:1-5-1-operating-systems:fib:10dfa0a2', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'fib', 'fib', 1, '{"question": "File management organises files into a structure of _____ so they can be found again easily.", "blankOptions": {"B1": ["system", "RAM", "folders", "buffer"]}}'::jsonb, '{"blanks": {"B1": "folders"}}'::jsonb),
('computer-science:1-5-1-operating-systems:match:d2c1931b', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Operating system”?", "options": ["System software that manages the hardware and provides a platform for applications to run on", "Software that lets the operating system communicate with a specific piece of hardware", "A graphical interface using windows, icons, menus and a pointer (WIMP)", "Provides user accounts, logins, passwords and access rights, keeping users separate"]}'::jsonb, '{"answer": 0, "explain": "“Operating system” means: System software that manages the hardware and provides a platform for applications to run on"}'::jsonb),
('computer-science:1-5-1-operating-systems:match:5a10d7e8', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “User interface”?", "options": ["The means by which a user interacts with the computer and gives it instructions", "Controls communication and the transfer of data between the computer and its devices", "The permissions that decide what a particular user is allowed to see or do", "An interface in which the user types text commands to control the computer"]}'::jsonb, '{"answer": 0, "explain": "“User interface” means: The means by which a user interacts with the computer and gives it instructions"}'::jsonb),
('computer-science:1-5-1-operating-systems:match:9818d3ab', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “GUI”?", "options": ["A temporary store for data waiting to be sent to a slower device such as a printer", "A graphical interface using windows, icons, menus and a pointer (WIMP)", "Rapidly switches one processor between several programs so they appear to run at once", "An interface in which the user types text commands to control the computer"]}'::jsonb, '{"answer": 1, "explain": "“GUI” means: A graphical interface using windows, icons, menus and a pointer (WIMP)"}'::jsonb),
('computer-science:1-5-1-operating-systems:match:fbe0d784', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Command line interface (CLI)”?", "options": ["Allocates RAM to programs and moves programs and data into and out of memory", "An interface in which the user types text commands to control the computer", "Rapidly switches one processor between several programs so they appear to run at once", "Controls communication and the transfer of data between the computer and its devices"]}'::jsonb, '{"answer": 1, "explain": "“Command line interface (CLI)” means: An interface in which the user types text commands to control the computer"}'::jsonb),
('computer-science:1-5-1-operating-systems:match:453c263d', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Memory management”?", "options": ["Organises files into folders and handles creating, renaming, moving and deleting them", "Allocates RAM to programs and moves programs and data into and out of memory", "An interface in which the user types text commands to control the computer", "System software that manages the hardware and provides a platform for applications to run on"]}'::jsonb, '{"answer": 1, "explain": "“Memory management” means: Allocates RAM to programs and moves programs and data into and out of memory"}'::jsonb),
('computer-science:1-5-1-operating-systems:match:0f69eec4', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Multitasking”?", "options": ["Rapidly switches one processor between several programs so they appear to run at once", "Controls communication and the transfer of data between the computer and its devices", "Provides user accounts, logins, passwords and access rights, keeping users separate", "A temporary store for data waiting to be sent to a slower device such as a printer"]}'::jsonb, '{"answer": 0, "explain": "“Multitasking” means: Rapidly switches one processor between several programs so they appear to run at once"}'::jsonb),
('computer-science:1-5-1-operating-systems:match:16ed4174', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Peripheral management”?", "options": ["Organises files into folders and handles creating, renaming, moving and deleting them", "Controls communication and the transfer of data between the computer and its devices", "Provides user accounts, logins, passwords and access rights, keeping users separate", "The permissions that decide what a particular user is allowed to see or do"]}'::jsonb, '{"answer": 1, "explain": "“Peripheral management” means: Controls communication and the transfer of data between the computer and its devices"}'::jsonb),
('computer-science:1-5-1-operating-systems:match:7b7e07b9', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Device driver”?", "options": ["The means by which a user interacts with the computer and gives it instructions", "Organises files into folders and handles creating, renaming, moving and deleting them", "Controls communication and the transfer of data between the computer and its devices", "Software that lets the operating system communicate with a specific piece of hardware"]}'::jsonb, '{"answer": 3, "explain": "“Device driver” means: Software that lets the operating system communicate with a specific piece of hardware"}'::jsonb),
('computer-science:1-5-1-operating-systems:match:dd826b16', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “User management”?", "options": ["Software that lets the operating system communicate with a specific piece of hardware", "Provides user accounts, logins, passwords and access rights, keeping users separate", "An interface in which the user types text commands to control the computer", "Organises files into folders and handles creating, renaming, moving and deleting them"]}'::jsonb, '{"answer": 1, "explain": "“User management” means: Provides user accounts, logins, passwords and access rights, keeping users separate"}'::jsonb),
('computer-science:1-5-1-operating-systems:match:3832aba2', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “File management”?", "options": ["The permissions that decide what a particular user is allowed to see or do", "Organises files into folders and handles creating, renaming, moving and deleting them", "Rapidly switches one processor between several programs so they appear to run at once", "System software that manages the hardware and provides a platform for applications to run on"]}'::jsonb, '{"answer": 1, "explain": "“File management” means: Organises files into folders and handles creating, renaming, moving and deleting them"}'::jsonb),
('computer-science:1-5-1-operating-systems:match:d0d697f8', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Buffer”?", "options": ["A graphical interface using windows, icons, menus and a pointer (WIMP)", "A temporary store for data waiting to be sent to a slower device such as a printer", "An interface in which the user types text commands to control the computer", "Organises files into folders and handles creating, renaming, moving and deleting them"]}'::jsonb, '{"answer": 1, "explain": "“Buffer” means: A temporary store for data waiting to be sent to a slower device such as a printer"}'::jsonb),
('computer-science:1-5-1-operating-systems:match:f5051aab', 'computer-science', 'computer-science:1-5-1-operating-systems', '1.5.1 Operating Systems', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Access rights”?", "options": ["Controls communication and the transfer of data between the computer and its devices", "Allocates RAM to programs and moves programs and data into and out of memory", "The permissions that decide what a particular user is allowed to see or do", "Rapidly switches one processor between several programs so they appear to run at once"]}'::jsonb, '{"answer": 2, "explain": "“Access rights” means: The permissions that decide what a particular user is allowed to see or do"}'::jsonb),
('computer-science:1-5-2-utility-software:exam:772f91c9', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'exam', 'mcq', 1, '{"num": "Q1", "question": "<p>Tick <strong>one</strong> box to identify the utility software that reorganises a disk so that each file''s pieces are stored together.</p>", "options": ["Encryption software", "Defragmentation software", "A diagnosis utility", "Backup software"], "hint": "Which utility is about tidying up how files are stored on the disk?"}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Defragmentation software</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "Defragmentation software."}'::jsonb),
('computer-science:1-5-2-utility-software:exam:2be29121', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'exam', 'mcq', 1, '{"num": "Q2", "question": "<p>Tick <strong>one</strong> box to identify the utility software that reduces the size of a file so it uses less storage.</p>", "options": ["Encryption software", "Data compression software", "A system information utility", "A firewall"], "hint": "The clue is ''reduces the size'' — only one utility makes files smaller."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Data compression software</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "Data compression software."}'::jsonb),
('computer-science:1-5-2-utility-software:exam:4be688c7', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'exam', 'mcq', 1, '{"num": "Q3", "question": "<p>Tick <strong>one</strong> box to identify which of these is a utility used for <strong>security</strong>.</p>", "options": ["A defragmenter", "Encryption software", "A system information utility", "A data compression tool"], "hint": "Which one protects data from being understood or attacked?"}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Encryption software</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "Encryption software."}'::jsonb),
('computer-science:1-5-2-utility-software:mcq:0fee0efb', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'mcq', 'mcq', 1, '{"question": "Utility software is best described as which type of software?", "options": ["Application software that the user opens to complete their own personal tasks, such as writing an essay", "System software that helps to maintain and optimise the computer", "A hardware upgrade that is fitted inside the computer to make it run faster and store much more data", "A programming language that is used by developers to write brand new programs from scratch each time"]}'::jsonb, '{"answer": 1, "explain": "Utility software is system software that maintains and optimises the computer — not application software, hardware or a programming language."}'::jsonb),
('computer-science:1-5-2-utility-software:mcq:1e7d8643', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'mcq', 'mcq', 1, '{"question": "What does a defragmentation utility do?", "options": ["It makes a second copy of every file and stores that copy safely on a separate drive in case of loss", "It reorganises the disk so each file''s pieces are stored together and the free space is collated", "It reduces the size of large files so that they take up much less space on the computer''s hard disk", "It scrambles the data on the disk using a key so that it cannot be understood by an attacker who steals it"]}'::jsonb, '{"answer": 1, "explain": "Defragmentation reorganises the disk so each file''s fragments are contiguous and free space is gathered. The others describe backup, compression and encryption."}'::jsonb),
('computer-science:1-5-2-utility-software:mcq:5c29a6d1', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'mcq', 'mcq', 1, '{"question": "Why can files be accessed more quickly after a hard disk has been defragmented?", "options": ["Because the total amount of free space on the hard disk is permanently and significantly increased by the process", "Because each file''s pieces are now together, so the read/write head moves less to read the whole file", "Because the hard disk is made to spin around at a much higher speed than it did before it was defragmented", "Because all of the files that had not been used for a long time are deleted to make everything else run faster"]}'::jsonb, '{"answer": 1, "explain": "With each file''s fragments stored together, the read/write head travels far less to read a whole file, so access is quicker. Defrag does not add free space or speed up the disk itself."}'::jsonb),
('computer-science:1-5-2-utility-software:mcq:29091a8b', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'mcq', 'mcq', 1, '{"question": "On which type of storage is defragmentation most useful?", "options": ["A solid state drive (SSD), because it has no moving parts and so benefits the most from being reorganised", "A magnetic hard disk drive (HDD), which has a moving read/write head", "A read-only optical disc such as a DVD that has already been finalised and cannot be written to again", "Cloud storage, because the files there are always physically fragmented across many far-apart servers"]}'::jsonb, '{"answer": 1, "explain": "Defragmentation helps HDDs, which have a moving read/write head. SSDs have no moving parts, so they gain little and are generally not defragmented."}'::jsonb),
('computer-science:1-5-2-utility-software:mcq:0d748351', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'mcq', 'mcq', 1, '{"question": "What does data compression software do to a file?", "options": ["It permanently protects the file so that only a person who has the correct secret key can ever open it", "It reduces the size of the file so it uses less storage and is faster to transfer", "It reorganises the pieces of the file so that they are all stored together in one continuous run on the disk", "It keeps a spare copy of the file on a separate device so that it can be restored if the original is lost"]}'::jsonb, '{"answer": 1, "explain": "Compression reduces file size (less storage, faster transfer). The other options describe encryption, defragmentation and backup."}'::jsonb),
('computer-science:1-5-2-utility-software:mcq:286a1c03', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'mcq', 'mcq', 1, '{"question": "Which utility software would help protect data so that it cannot be understood if it is stolen?", "options": ["A defragmentation utility, because it tidies up the disk and makes the files harder for a thief to locate", "Encryption software", "A system information utility, because it can display exactly which files are currently stored on the computer", "A data compression utility, because it makes the files so small that an attacker would not notice them at all"]}'::jsonb, '{"answer": 1, "explain": "Encryption scrambles data so it is unreadable without the key — the correct security utility here. The others do not protect data from being understood."}'::jsonb),
('computer-science:1-5-2-utility-software:mcq:9ce3e7e2', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'mcq', 'mcq', 1, '{"question": "A company copies only the files that have changed since its last backup. Which type of backup is this?", "options": ["A full backup", "An incremental backup", "A compressed daily backup", "An encrypted backup"]}'::jsonb, '{"answer": 1, "explain": "Copying only what has changed since the last backup is an incremental backup; a full backup copies everything every time."}'::jsonb),
('computer-science:1-5-2-utility-software:mcq:38728700', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'mcq', 'mcq', 1, '{"question": "Which of these is a disadvantage of using only full backups every time?", "options": ["They copy only the files that have recently changed, so a lot of important older data is never actually saved", "They are slow to make and use a large amount of storage, because everything is copied every time", "They cannot be used to restore data at all if the computer''s original hard drive completely fails one day", "They can only ever be carried out after an incremental backup of the same data has first been completed"]}'::jsonb, '{"answer": 1, "explain": "A full backup copies everything each time, so it is slow and storage-heavy. (Incremental copies only changes; and incremental — not full — needs a prior full backup.)"}'::jsonb),
('computer-science:1-5-2-utility-software:mcq:02bd93d6', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'mcq', 'mcq', 1, '{"question": "What does a system information utility do?", "options": ["It scrambles the computer''s data with a key so that it stays completely private and secure from any attacker", "It reports details about the computer, such as its processor, amount of RAM and operating system version", "It reorganises the files stored on the hard disk so that each one is kept together and loads more quickly", "It automatically copies the user''s most important files to a separate drive every night while they are asleep"]}'::jsonb, '{"answer": 1, "explain": "A system information utility reports details about the computer''s hardware and software. The others describe encryption, defragmentation and backup."}'::jsonb),
('computer-science:1-5-2-utility-software:mcq:f501ef69', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'mcq', 'mcq', 1, '{"question": "A utility tests a computer''s hardware, finds errors and reports what is wrong. Which utility is this?", "options": ["A defragmentation utility", "A diagnosis (diagnostic) utility", "A data compression and archiving utility", "An encryption utility"]}'::jsonb, '{"answer": 1, "explain": "Finding faults and reporting what is wrong is the job of a diagnosis (diagnostic) utility."}'::jsonb),
('computer-science:1-5-2-utility-software:mcq:0942f089', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'mcq', 'mcq', 1, '{"question": "Which list contains only utilities that are used for security?", "options": ["Defragmenter, data compression and a file transfer tool that moves files between two different folders", "Antivirus, firewall and encryption software", "Data compression, a system information utility and a diagnosis utility used for finding hardware faults", "Backup software, defragmentation software and a utility that reports how much RAM the computer has fitted"]}'::jsonb, '{"answer": 1, "explain": "Antivirus, firewall and encryption are all security utilities. The other lists contain disk-organisation, information and backup utilities."}'::jsonb),
('computer-science:1-5-2-utility-software:mcq:a7b5afa7', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'mcq', 'mcq', 1, '{"question": "Why might a user run both full and incremental backups rather than only full backups?", "options": ["Because incremental backups are able to copy files even when the computer is switched completely off at the wall", "Because the incremental backups are much faster and use less storage in between the occasional full backups", "Because an incremental backup does not need any full backup to have been made before it at any point at all", "Because full backups are the only kind that can ever be restored, so the incremental ones are just extra copies"]}'::jsonb, '{"answer": 1, "explain": "Incremental backups are quick and storage-light between fuller backups, giving complete cover without copying everything every time."}'::jsonb),
('computer-science:1-5-2-utility-software:tf:386a517e', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'tf', 'tf', 1, '{"question": "Utility software is a type of application software used for tasks like writing documents."}'::jsonb, '{"answer": false, "explain": "Utility software is system software that maintains the computer. Applications (like a word processor) are for the user''s own tasks."}'::jsonb),
('computer-science:1-5-2-utility-software:tf:fe664adb', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'tf', 'tf', 1, '{"question": "Defragmentation reorganises a disk so that each file''s pieces are stored together."}'::jsonb, '{"answer": true, "explain": "Correct — defragmentation collates each file''s fragments so they are contiguous, and gathers the free space together."}'::jsonb),
('computer-science:1-5-2-utility-software:tf:798c9ef7', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'tf', 'tf', 1, '{"question": "Files can be accessed faster after defragmentation because the read/write head has to move less."}'::jsonb, '{"answer": true, "explain": "Correct — with each file''s pieces together, the head travels far less to read the whole file, so access is quicker."}'::jsonb),
('computer-science:1-5-2-utility-software:tf:8476e4ac', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'tf', 'tf', 1, '{"question": "Defragmentation increases the total amount of free space on the hard disk."}'::jsonb, '{"answer": false, "explain": "Defragmentation does not create extra free space — it reorganises existing data so files are contiguous and free space is gathered together."}'::jsonb),
('computer-science:1-5-2-utility-software:tf:9ba82a97', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'tf', 'tf', 1, '{"question": "Data compression reduces the size of a file so it uses less storage and transfers faster."}'::jsonb, '{"answer": true, "explain": "Correct — compression encodes the data more efficiently, so the file is smaller and there is less data to send."}'::jsonb),
('computer-science:1-5-2-utility-software:tf:e8c9f46a', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'tf', 'tf', 1, '{"question": "An incremental backup copies every file on the computer each time it runs."}'::jsonb, '{"answer": false, "explain": "That describes a full backup. An incremental backup copies only the files that have changed since the last backup."}'::jsonb),
('computer-science:1-5-2-utility-software:tf:0e58568d', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'tf', 'tf', 1, '{"question": "An incremental backup can only be made after a full backup has already been completed."}'::jsonb, '{"answer": true, "explain": "Correct — incremental backups record changes since the last backup, so there must be a full backup to build on first."}'::jsonb),
('computer-science:1-5-2-utility-software:tf:2f3c5032', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'tf', 'tf', 1, '{"question": "A system information utility is used to find and remove malware from the computer."}'::jsonb, '{"answer": false, "explain": "A system information utility reports details about the computer (processor, RAM, OS). Removing malware is the job of anti-malware software."}'::jsonb),
('computer-science:1-5-2-utility-software:learn:9c12250d', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'learn', 'mcq', 1, '{"readingTitle": "What is utility software?", "reading": "<h4>Small tools that help maintain the computer</h4>\n<ul>\n<li><strong>Utility software</strong> is a type of <strong>system software</strong>: programs that help to <strong>maintain, configure and optimise</strong> a computer so it keeps running smoothly. This is often called <strong>\"housekeeping\"</strong> or maintenance.</li>\n<li>Each utility does one specific maintenance job — for example tidying up the hard disk, making files smaller, keeping data safe, or checking the system for problems.</li>\n<li>Utilities are <strong>not</strong> application software: applications (like a word processor) are for the user''s own tasks, whereas utilities work behind the scenes to look after the <strong>computer itself</strong>.</li>\n</ul>\n<h4>The utilities you should know</h4>\n<ul>\n<li>The three named in the specification are <strong>defragmentation</strong>, <strong>data compression</strong> and <strong>encryption software</strong>. Exam questions also use others: <strong>backup</strong>, <strong>system information</strong>, <strong>diagnosis</strong>, and security tools such as <strong>anti-malware</strong> and <strong>firewalls</strong>.</li>\n</ul>", "question": "Which statement best describes utility software?", "options": ["Application software that a user opens to carry out a personal task such as writing a letter or editing a photograph", "System software that helps to maintain, configure and optimise the computer so it keeps running well", "A physical hardware component that is fitted inside the computer to speed up how quickly it can run", "The single main program that manages all of the computer''s hardware and runs every other program"]}'::jsonb, '{"answer": 1, "explain": "Utility software is system software that maintains and optimises the computer (housekeeping) — it is not an application, hardware, or the operating system itself."}'::jsonb),
('computer-science:1-5-2-utility-software:learn:dba668bf', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'learn', 'mcq', 1, '{"readingTitle": "Why does a hard disk become fragmented?", "reading": "<h4>Files get split up and scattered over time</h4>\n<ul>\n<li>When a file is first saved, its data is usually stored in one continuous run of space on the disk.</li>\n<li>But as files are <strong>edited, deleted and new ones saved</strong>, gaps of free space appear all over the disk. To use that space, the computer starts <strong>splitting files into pieces (fragments)</strong> and storing the pieces in whatever gaps are available.</li>\n<li>Over time, a single file can end up <strong>scattered across many different parts of the disk</strong>, and the free space becomes scattered too. This is called <strong>fragmentation</strong>.</li>\n</ul>", "question": "Why does a hard disk gradually become fragmented?", "options": ["Because the computer deliberately damages old files to free up extra space for new ones it needs", "Because as files are edited, deleted and saved, files get split into pieces stored in scattered gaps", "Because the read/write head physically wears down the surface of the disk a little more each day", "Because fragmentation is something the user has to switch on manually before it can ever happen at all"]}'::jsonb, '{"answer": 1, "explain": "Editing, deleting and saving files leaves scattered gaps, so the computer stores files in pieces across those gaps — that scattering is fragmentation."}'::jsonb),
('computer-science:1-5-2-utility-software:learn:d7c33120', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'learn', 'mcq', 1, '{"readingTitle": "What defragmentation does — and why it speeds things up", "reading": "<h4>Putting each file''s pieces back together</h4>\n<ul>\n<li>A <strong>defragmentation</strong> utility reorganises the data on the disk so that all the pieces of each file are stored <strong>together (contiguously)</strong>, one after another, and the <strong>free space is collated</strong> (gathered) into one area.</li>\n<li><strong>Why files are then accessed faster:</strong> when a file is fragmented, the read/write head has to <strong>move to many different places</strong> on the disk to gather all its pieces. After defragmentation, each file''s pieces are together, so the head <strong>moves far less</strong> to read the whole file — making access quicker.</li>\n<li><strong>Important:</strong> defragmentation is mainly useful for <strong>magnetic hard disk drives (HDDs)</strong>, which have a moving read/write head. <strong>Solid state drives (SSDs)</strong> have no moving parts, so defragmentation gives little benefit and is generally not done on them.</li>\n</ul>", "question": "Why can a computer access files more quickly after its hard disk has been defragmented?", "options": ["Because defragmentation permanently deletes any of the files that the user has not opened recently, so as to save room", "Because each file''s pieces are now stored together, so the read/write head moves less to read the whole file", "Because defragmentation physically increases the total speed at which the disk itself is able to spin round", "Because the computer is given a completely new and much faster hard disk during the defragmentation process"]}'::jsonb, '{"answer": 1, "explain": "Defragmentation stores each file''s fragments contiguously, so the read/write head travels much less to read a whole file — that is what speeds up access."}'::jsonb),
('computer-science:1-5-2-utility-software:learn:41b1cd48', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'learn', 'mcq', 1, '{"readingTitle": "Data compression", "reading": "<h4>Making files smaller</h4>\n<ul>\n<li><strong>Data compression</strong> software <strong>reduces the size</strong> of a file — the number of bytes it takes up — by encoding the same data more efficiently.</li>\n<li><strong>Why it is useful:</strong> smaller files take up <strong>less storage space</strong>, and they are <strong>faster to send</strong> across a network or the internet (uploading, downloading or emailing), because there is less data to transfer.</li>\n<li>Common examples: creating a <strong>ZIP</strong> file, and the compression built into image, audio and video formats (such as JPEG or MP3).</li>\n</ul>", "question": "Why is it useful to compress a file before emailing it to someone?", "options": ["Because compressing the file will automatically translate it into a different language for the person receiving it", "Because a compressed file is smaller, so it uses less storage and is faster to send across the internet", "Because compression permanently protects the file so that it can never be opened by the wrong person again", "Because a compressed file will always open much more quickly on absolutely any computer that receives it later"]}'::jsonb, '{"answer": 1, "explain": "Compression reduces file size, so the file uses less storage and there is less data to transfer, making it faster to send."}'::jsonb),
('computer-science:1-5-2-utility-software:learn:875bbe10', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'learn', 'mcq', 1, '{"readingTitle": "Encryption software", "reading": "<h4>Scrambling data so it cannot be understood</h4>\n<ul>\n<li><strong>Encryption software</strong> scrambles data using an algorithm and a <strong>key</strong>, so that the data cannot be understood by anyone who does not have the key.</li>\n<li>Only someone with the correct <strong>key</strong> can <strong>decrypt</strong> the data back into its original, readable form.</li>\n<li><strong>Why it is used:</strong> if the data is <strong>intercepted or stolen</strong>, it is meaningless to the attacker without the key — so encryption is a <strong>security</strong> utility, protecting data both while it is stored and while it is being sent. (You met encryption as a defence in <strong>1.4.2</strong>.)</li>\n</ul>", "question": "What does encryption software do to a file?", "options": ["It makes the file much smaller so that it takes up noticeably less room on the computer''s hard drive", "It scrambles the data using a key so it cannot be understood by anyone who does not have that key", "It reorganises the pieces of the file so that they are all stored together in one place on the disk", "It creates a second copy of the file and stores that copy safely on a completely separate storage device"]}'::jsonb, '{"answer": 1, "explain": "Encryption scrambles the data with a key so it is unreadable without the key. Making files smaller is compression; reorganising pieces is defragmentation; a spare copy is backup."}'::jsonb),
('computer-science:1-5-2-utility-software:learn:0210c99e', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'learn', 'mcq', 1, '{"readingTitle": "Backup software", "reading": "<h4>Keeping a spare copy of your data</h4>\n<ul>\n<li><strong>Backup software</strong> makes a <strong>spare copy</strong> of files and data, usually stored <strong>separately</strong> (for example on an external drive or in the cloud), so the data can be <strong>restored</strong> if the original is lost.</li>\n<li>It protects against data loss from <strong>hardware failure, accidental deletion, theft, or a malware attack</strong> such as ransomware.</li>\n<li>Backups can be <strong>scheduled</strong> to run automatically (e.g. every night), so the copy is kept up to date without the user having to remember.</li>\n</ul>", "question": "What is the main purpose of backup software?", "options": ["To make each of the original files a good deal smaller so that many more of them can fit onto the same storage device", "To keep a spare copy of data, stored separately, so it can be restored if the original is lost or damaged", "To scramble the data using a secret key so that nobody without the key is able to read the files", "To reorganise the files on the disk so that each one is stored together and can be opened more quickly"]}'::jsonb, '{"answer": 1, "explain": "Backup keeps a separate spare copy so data can be restored after loss. Making files smaller is compression, scrambling is encryption, and reorganising is defragmentation."}'::jsonb),
('computer-science:1-5-2-utility-software:learn:69ba5302', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'learn', 'mcq', 1, '{"readingTitle": "Full vs incremental backups", "reading": "<h4>Two ways of making a backup</h4>\n<ul>\n<li>A <strong>full backup</strong> copies <strong>every</strong> file and all of the data, every time. It is <strong>complete</strong>, but it is <strong>slow</strong> and uses a <strong>lot of storage</strong>.</li>\n<li>An <strong>incremental backup</strong> copies <strong>only the files that have changed</strong> since the last backup. It is much <strong>faster</strong> and uses <strong>less storage</strong> each time.</li>\n<li><strong>The catch:</strong> an incremental backup can only be done <strong>after a full backup</strong> has been made. And to <strong>restore</strong> everything you need the full backup <strong>plus every incremental</strong> since — so restoring is more complicated.</li>\n<li>Many people use <strong>both</strong>: an occasional full backup, then quick incremental backups in between — getting complete cover without backing up everything every single time.</li>\n</ul>", "question": "How does an incremental backup differ from a full backup?", "options": ["An incremental backup copies absolutely every file and all of the data on the computer every single time it runs", "An incremental backup copies only the files that have changed since the last backup, so it is faster", "An incremental backup permanently deletes the older files once it has finished copying the newest ones across", "An incremental backup can be made before any full backup has ever been carried out on the computer at all"]}'::jsonb, '{"answer": 1, "explain": "An incremental backup copies only what has changed since the last backup (faster, less storage); a full backup copies everything every time."}'::jsonb),
('computer-science:1-5-2-utility-software:learn:463323e4', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'learn', 'mcq', 1, '{"readingTitle": "System information & diagnosis utilities", "reading": "<h4>Checking on the computer''s health</h4>\n<ul>\n<li>A <strong>system information</strong> utility <strong>reports details about the computer</strong> — such as the processor, how much RAM is fitted, the operating system version, and how much storage is free. This helps a user or technician check the specification and see how the system is set up.</li>\n<li>A <strong>diagnosis</strong> (diagnostic) utility helps to <strong>find faults and problems</strong> — for example testing hardware, checking for errors, and reporting what is wrong so it can be fixed.</li>\n<li>Together they let you <strong>see what a computer has</strong> (system information) and <strong>find out what is wrong with it</strong> (diagnosis).</li>\n</ul>", "question": "What is the purpose of a diagnosis (diagnostic) utility?", "options": ["To display a simple list showing the processor, the amount of RAM and the version of the operating system", "To test the system and find faults or errors, then report what is wrong so that it can be fixed", "To make a spare copy of the user''s important files and store it safely on a separate external drive", "To reduce the size of the largest files on the computer so that they take up much less storage space"]}'::jsonb, '{"answer": 1, "explain": "A diagnosis utility finds and reports faults/errors. Listing the specification is what a system information utility does; the others describe backup and compression."}'::jsonb),
('computer-science:1-5-2-utility-software:learn:54cca4ae', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'learn', 'mcq', 1, '{"readingTitle": "Classifying utilities: security or maintenance?", "reading": "<h4>Sorting utilities by what they are for</h4>\n<p>A common question gives you a list of utilities and asks you to sort them by <strong>purpose</strong>. Learn which group each one belongs to:</p>\n<ul>\n<li><strong>Security utilities</strong> — protect data and the system from attack: <strong>anti-malware/antivirus</strong>, <strong>firewall</strong>, and <strong>encryption software</strong>.</li>\n<li><strong>Disk organisation / maintenance utilities</strong> — keep the storage tidy and efficient: <strong>defragmentation</strong>, <strong>data compression</strong>, and <strong>file transfer/management</strong> tools.</li>\n<li><strong>Backup</strong> keeps your data safe from loss, and <strong>system information / diagnosis</strong> keep the computer healthy and help fix problems.</li>\n</ul>\n<p>If a question asks whether a utility is used for <strong>security</strong> or <strong>disk organisation</strong>, think: does it protect against attackers (security), or tidy/manage the storage (disk organisation)?</p>", "question": "In a ''security or disk organisation'' sorting question, which utility belongs under disk organisation?", "options": ["A firewall, because it carefully monitors and filters all of the traffic coming into and out of the network", "A defragmenter, because it reorganises the files on the disk so they are stored together and tidily", "An antivirus, because it scans the computer''s files and then removes any malicious software that it finds", "Encryption software, because it scrambles the data so that it cannot be read by an attacker without a key"]}'::jsonb, '{"answer": 1, "explain": "A defragmenter organises the disk, so it is a disk-organisation utility. A firewall, antivirus and encryption are all security utilities."}'::jsonb),
('computer-science:1-5-2-utility-software:misc:4fd1d303', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking defragmentation creates extra free space or deletes files to make room.</p><p><strong>✅ The correct idea:</strong> Defragmentation does <strong>not</strong> add free space or delete your files. It <strong>reorganises</strong> the data that is already there so each file''s pieces are stored <strong>together</strong>, and gathers the scattered free space into one area. The benefit is <strong>faster access</strong>, not more storage.</p>", "question": "What is the real benefit of defragmentation?", "options": ["It permanently increases the total amount of free storage space that is currently available on the computer''s own hard disk", "It reorganises files so their pieces are together, letting the read/write head move less and access them faster", "It deletes all of the files that the user has not opened for a long time in order to free up extra room", "It creates an extra backup copy of every file so that nothing can ever be lost from the computer again"]}'::jsonb, '{"answer": 1, "explain": "Defragmentation reorganises existing data for faster access — it does not add free space, delete files, or make backups."}'::jsonb),
('computer-science:1-5-2-utility-software:misc:10e0e33b', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing that compressing a file loses or deletes some of your data.</p><p><strong>✅ The correct idea:</strong> Compression <strong>reduces the size</strong> of a file by storing the same information more efficiently. With <strong>lossless</strong> compression (like a ZIP file) the original data is restored <strong>exactly</strong> when it is decompressed — your files are not deleted or lost, just packed more tightly.</p>", "question": "What happens to a file when it is compressed using lossless compression?", "options": ["Some of the file''s data is permanently thrown away, so the file can never be returned to how it was before", "The file is made smaller by storing the same data more efficiently, and can be restored exactly later", "The file is scrambled with a secret key so that nobody is able to read it without first being given the key", "The file is copied onto a completely separate storage device and the original version is then deleted for good"]}'::jsonb, '{"answer": 1, "explain": "Lossless compression makes the file smaller by encoding it more efficiently and restores the original exactly — nothing is lost. Scrambling is encryption; copying is backup."}'::jsonb)
